import{_ as t,o as e,c as r,ag as s}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/2.BeDx08xP.jpg",i="/kaiping-reports/assets/3.Bns3TpDZ.jpg",n="/kaiping-reports/assets/5.C8fW65O4.jpg",l="/kaiping-reports/assets/6.CWPvYJX7.jpg",p="/kaiping-reports/assets/8.xXJ2DI_u.jpg",h="/kaiping-reports/assets/7.Dl6uPbb8.jpg",f=JSON.parse('{"title":"专业调研报告内容：","description":"","frontmatter":{},"headers":[],"relativePath":"reports/马依然/马依然_赤坎古镇建筑调研报告.md","filePath":"reports/马依然/马依然_赤坎古镇建筑调研报告.md"}'),_={name:"reports/马依然/马依然_赤坎古镇建筑调研报告.md"};function c(d,a,m,u,g,b){return e(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="专业调研报告内容" tabindex="-1">专业调研报告内容： <a class="header-anchor" href="#专业调研报告内容" aria-label="Permalink to &quot;专业调研报告内容：&quot;">​</a></h1><h1 id="一、" tabindex="-1">一、 <a class="header-anchor" href="#一、" aria-label="Permalink to &quot;一、&quot;">​</a></h1><p><img src="'+o+'" alt="2"> <img src="'+i+'" alt="3"><strong>二、</strong> <strong>空间类型与形态</strong> 从建筑类型来看，古镇核心街巷以骑楼街为主体，堤西路、中华路等主要街道骑楼连续分布，形成长约 3 公里的线性公共空间。骑楼底层立柱支撑形成连续廊檐，宽约 3-4 米，既为行人遮风挡雨，也成为商业活动的延伸空间。次级巷道狭窄曲折，宽度多在 1-2 米，连接主街与内部民居，空间尺度亲切，构成 “主街 — 次巷 — 内院” 的层级体系。街巷走向顺应水势，局部转折自然，满足高效的交通功能需求。 古镇建筑以骑楼为核心类型，多为 2-3 层，局部 4 层，采用 “下铺上宅、前铺后宅” 的复合空间模式。立面呈现强烈的中西合璧特征：底层为连续拱廊，借鉴古罗马建筑范式；二层及以上融入巴洛克浮雕、山花装饰、罗马柱式等西洋元素；顶部搭配岭南传统灰塑、瓦顶与满洲窗。单体建筑面宽窄、进深深，呈长筒型布局，内部常设天井采光通风，形成 “外欧内粤” 的空间特质。此外，司徒氏图书馆、关族图书馆等公共建筑，以葡萄牙建筑风格为主，兼具宗族象征与文化功能，成为古镇空间节点。</p><h1 id="三、" tabindex="-1">三、 <a class="header-anchor" href="#三、" aria-label="Permalink to &quot;三、&quot;">​</a></h1><p>主体建造材料分为三个部分：</p><p>传统材料：清末建筑以砖木结构为主，墙体用青砖砌筑，木梁架支撑瓦顶。民国时期骑楼主体以红砖、青砖为墙体材料，柱、梁、楼板部分采用钢筋混凝土，兼顾坚固性与可塑性。屋面覆盖传统陶瓦，防水隔热；门窗多用硬木，搭配彩色玻璃、满洲窗，兼具装饰与实用功能。</p><p>外来材料：华侨归国建设时引入水泥、钢筋、玻璃等西洋建材，用于建筑立面装饰、结构加固与细节构建，如巴洛克式浮雕、罗马柱、铁艺栏杆等，丰富了建筑构造层次。</p><p>装饰材料：立面装饰以灰塑、石雕、木雕为主，灰塑用于山花、檐口，题材多为花鸟、几何纹样；石雕应用于柱础、门框；木雕集中于室内屏风、花窗，工艺精湛。</p><p><img src="'+n+'" alt="5"></p><h1 id="四、" tabindex="-1">四、 <a class="header-anchor" href="#四、" aria-label="Permalink to &quot;四、&quot;">​</a></h1><h1 id="一-历史功能布局" tabindex="-1">（一）历史功能布局 <a class="header-anchor" href="#一-历史功能布局" aria-label="Permalink to &quot;（一）历史功能布局&quot;">​</a></h1><p><img src="'+l+'" alt="6"></p><p><img src="'+p+'" alt="8"><img src="'+h+'" alt="7"></p><h1 id="二-传统使用方式" tabindex="-1">（二）传统使用方式 <a class="header-anchor" href="#二-传统使用方式" aria-label="Permalink to &quot;（二）传统使用方式&quot;">​</a></h1><h1 id="三-功能演变" tabindex="-1">（三）功能演变 <a class="header-anchor" href="#三-功能演变" aria-label="Permalink to &quot;（三）功能演变&quot;">​</a></h1><h1 id="五、" tabindex="-1">五、 <a class="header-anchor" href="#五、" aria-label="Permalink to &quot;五、&quot;">​</a></h1><h1 id="一-文旅利用现状" tabindex="-1">（一）文旅利用现状 <a class="header-anchor" href="#一-文旅利用现状" aria-label="Permalink to &quot;（一）文旅利用现状&quot;">​</a></h1><h1 id="二-适应性改造措施" tabindex="-1">（二)适应性改造措施 <a class="header-anchor" href="#二-适应性改造措施" aria-label="Permalink to &quot;（二)适应性改造措施&quot;">​</a></h1>',18)])])}const k=t(_,[["render",c]]);export{f as __pageData,k as default};
